sys_script_fix.script:
// SVEM - Rewrite Dashboard as Self-Contained Page
// Replaces the broken NowSDK/UX framework dashboard with a self-contained HTML/JS version.

var htmlB64 = "";

var csB64 = "";

var htmlContent = GlideStringUtil.base64Decode(htmlB64);
var csContent = GlideStringUtil.base64Decode(csB64);

var gr = new GlideRecord('sys_ui_page');
gr.addQuery('name', 'dashboard');
gr.addQuery('sys_scope', '83b23c9493500310414ef2375d03d6d7');
gr.query();

if (gr.next()) {
    gr.setValue('html', htmlContent);
    gr.setValue('client_script', csContent);
    gr.setValue('direct', 'false');
    gr.update();
    gs.info('SVEM Dashboard page updated successfully. sys_id: ' + gr.getUniqueValue());
} else {
    gs.warn('SVEM Dashboard page not found.');
}
